insert into mastery_checks
  (id, slug, scope, lesson_id, module_id, level, title, description, question_count, pass_threshold, cooldown_hours, status) values
  ($lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, $lum$everyday-work-module-check$lum$, $lum$module$lum$, NULL, $lum$a529e901-a3fd-5ab8-890d-11e289b52db2$lum$::uuid, NULL, $lum$Everyday work: test out$lum$, $lum$Already use AI smoothly for meetings, email, and documents? Pass this and the whole Everyday work module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published'),
  ($lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, $lum$creation-module-check$lum$, $lum$module$lum$, NULL, $lum$811fb775-9241-5709-87bb-bfc2cf64c2db$lum$::uuid, NULL, $lum$Creation: test out$lum$, $lum$Comfortable drafting, editing in your voice, repurposing, and making images with AI? Pass this and the whole Creation module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published'),
  ($lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, $lum$business-workflows-module-check$lum$, $lum$module$lum$, NULL, $lum$4fff1d1f-a4e8-5b0d-8b5a-9aee6a95e4fa$lum$::uuid, NULL, $lum$Business workflows: test out$lum$, $lum$Already build repeatable AI workflows, templates, and research routines? Pass this and the whole Business workflows module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published'),
  ($lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, $lum$industry-deep-dives-module-check$lum$, $lum$module$lum$, NULL, $lum$52bf84a8-edd6-5b0b-93f3-fcd138f3658d$lum$::uuid, NULL, $lum$Industry deep dives: test out$lum$, $lum$Confident applying AI safely in a professional field, with the right accuracy and privacy guardrails? Pass this and the whole Industry deep dives module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published'),
  ($lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, $lum$building-with-ai-module-check$lum$, $lum$module$lum$, NULL, $lum$a2671a81-7114-5587-8321-da5fa352bbc5$lum$::uuid, NULL, $lum$Building with AI: test out$lum$, $lum$Already chain prompts, keep a personal toolkit, and build templates your team adopts? Pass this and the whole Building with AI module leaves your path, marked complete.$lum$, 8, 0.8, 24, 'published')
insert into mastery_check_questions
  (id, check_id, order_index, type, content, source_block_id) values
  ($lum$90153cf0-9774-513a-a682-53750f420d8e$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"You want AI to summarize a long report. What makes the summary genuinely useful to you?","options":[{"id":"a","label":"Asking simply to summarize it, so you get a neutral shorter version","is_correct":false,"explanation":"A plain summary is still generic and not aimed at your decision. Telling the AI your purpose is what makes it useful."},{"id":"b","label":"Telling the AI who you are and what you need to decide, so it pulls only the relevant parts","is_correct":true,"explanation":"A good summary is shaped by your purpose. Naming your role and decision filters out the noise."},{"id":"c","label":"Asking for the longest possible summary so nothing is missed","is_correct":false,"explanation":"Length is not the goal. A focused summary aimed at your decision beats an exhaustive one."}]}$lum$::jsonb, NULL),
  ($lum$dae23b1c-f144-5da8-a927-37293c269152$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What is the strongest way to use AI before an important meeting?","options":[{"id":"a","label":"Ask it to attend the meeting for you","is_correct":false,"explanation":"AI prepares you, it does not replace your presence or judgment in the room."},{"id":"b","label":"Have it draft an agenda, surface questions you should be ready for, and name likely objections","is_correct":true,"explanation":"Using AI to think through the meeting ahead of time is where the value is."},{"id":"c","label":"Ask it who will be the most difficult person in the room","is_correct":false,"explanation":"AI does not know the people in your meeting. It helps with structure and likely objections, not office politics."}]}$lum$::jsonb, NULL),
  ($lum$b0fe8f0b-cd61-5ae0-8d91-a87b8c17e6e0$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"When drafting a professional email with AI, what produces the best result?","options":[{"id":"a","label":"Asking it to write a professional email with no other detail","is_correct":false,"explanation":"That gives a hollow template. The good material comes from your specifics."},{"id":"b","label":"Giving it the situation, the key points to make, the tone, and a length limit","is_correct":true,"explanation":"Feeding it the raw material is what turns a generic draft into something close to ready."},{"id":"c","label":"Letting it send the email automatically once written","is_correct":false,"explanation":"You always read before sending. The AI does not know the one detail that may change everything."}]}$lum$::jsonb, NULL),
  ($lum$3b31aeea-8dba-56b3-9af4-aac307183772$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Why does splitting writing into a brain-dump then an AI cleanup work so well?","options":[{"id":"a","label":"Because the AI writes better when it has no input from you","is_correct":false,"explanation":"The opposite is true. The AI needs your raw thinking to keep the result yours."},{"id":"b","label":"Because the hard part is having the ideas, so you do that and let AI handle the arranging","is_correct":true,"explanation":"Separating thinking from polishing removes the blank-page freeze and keeps your meaning."},{"id":"c","label":"Because it lets you avoid reading the final result","is_correct":false,"explanation":"You still read the result to confirm the AI did not change your meaning."}]}$lum$::jsonb, NULL),
  ($lum$95e09be0-cc92-5378-8255-fb55b787c411$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"You used AI to get oriented on a new regulation. Which part most needs verifying before you rely on it?","options":[{"id":"a","label":"The plain-language overview of the topic","is_correct":false,"explanation":"General orientation is a fine starting map and exactly what AI does well."},{"id":"b","label":"The exact dates, dollar thresholds, and citations it provided","is_correct":true,"explanation":"Hard specifics are the most likely to be invented. Confirm each against an official source."},{"id":"c","label":"The list of questions it suggested you research","is_correct":false,"explanation":"Surfacing questions to investigate is a strong, low-risk use of AI."}]}$lum$::jsonb, NULL),
  ($lum$4fed2b1d-4936-549a-9d06-df7d597a6d92$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What is the point of using rough, messy notes as input to an AI debrief?","options":[{"id":"a","label":"Messy notes always produce better answers than clear ones","is_correct":false,"explanation":"Clear notes are fine too. The point is you do not have to clean them up first."},{"id":"b","label":"AI handles fragments and abbreviations well, so you can capture value while it is fresh","is_correct":true,"explanation":"You extract the value quickly and let the AI handle the formatting."},{"id":"c","label":"You must always format notes perfectly before pasting them","is_correct":false,"explanation":"That defeats the time savings. The AI can work from rough input."}]}$lum$::jsonb, NULL),
  ($lum$e95ea4de-099e-594b-a623-879d71aa7dc4$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 6, $lum$fill_blank$lum$, $lum${"template":"A useful AI summary is shaped by your {{1}}, so tell it who you are and what you need to decide.","blanks":[{"id":"1","accept":["purpose","goal","need"],"ideal":"purpose"}],"explanation":"Purpose is what turns a generic recap into a summary aimed at your decision."}$lum$::jsonb, NULL),
  ($lum$743edfc0-f1d1-5fe4-aef7-ec9b4156734d$lum$::uuid, $lum$0d508922-ae95-5b95-89f9-cb41e377459f$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Before you send any AI-drafted email, you should always {{1}} it, because the AI does not know your full context.","blanks":[{"id":"1","accept":["read","review","check"],"ideal":"read"}],"explanation":"The AI drafts, you decide. A quick read catches the detail only you know."}$lum$::jsonb, NULL),
  ($lum$f7ea59f9-1799-510f-b531-894282f60dad$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"Why is generating a first draft with AI so valuable even when the draft is only a B-minus?","options":[{"id":"a","label":"Because editing something rough is far easier than starting from a blank page","is_correct":true,"explanation":"A B-minus you can edit beats an A-plus you never start. AI removes the hardest part."},{"id":"b","label":"Because the first draft is always good enough to publish as is","is_correct":false,"explanation":"It rarely is. The value is that you now have something to shape."},{"id":"c","label":"Because it means you no longer have to think about the topic","is_correct":false,"explanation":"Your thinking is exactly what makes the draft worth editing. You stay involved."}]}$lum$::jsonb, NULL),
  ($lum$f11cf065-a67e-5a3a-bc44-275c15eeaafb$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What is the most reliable way to get AI to write in your voice?","options":[{"id":"a","label":"Ask it to be more creative","is_correct":false,"explanation":"Vague requests do not teach it your voice. It needs examples and specifics."},{"id":"b","label":"Paste samples of your own writing and name your style traits for it to copy","is_correct":true,"explanation":"Showing real examples plus naming your traits steers the output hard toward you."},{"id":"c","label":"Use the longest possible prompt","is_correct":false,"explanation":"Length is not the point. Concrete examples of your writing are what matter."}]}$lum$::jsonb, NULL),
  ($lum$7dba6d37-e86d-59a4-b869-c0f688480fa5$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"What makes content repurposing with AI work so well?","options":[{"id":"a","label":"AI invents brand new ideas for each format","is_correct":false,"explanation":"The ideas stay the same. Only the format and tone change."},{"id":"b","label":"AI is good at preserving your meaning while changing the form for a new audience","is_correct":true,"explanation":"You did the hard part. Reshaping the same ideas for a new channel is the easy part."},{"id":"c","label":"It removes the need to consider the audience at all","is_correct":false,"explanation":"Different audiences need different things, so each version still deserves a quick check."}]}$lum$::jsonb, NULL),
  ($lum$6854a74c-fa66-531c-81a4-1d49d7896d7f$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"How do you keep an AI-assisted presentation from looking generic and AI-made?","options":[{"id":"a","label":"Let AI generate the whole finished deck from a one-line topic","is_correct":false,"explanation":"That produces vague bullets and filler. It is exactly the look you want to avoid."},{"id":"b","label":"Use AI for the structure and wording, but supply your own real numbers, examples, and proof","is_correct":true,"explanation":"Structure from AI, substance from you. That combination is fast and authentic."},{"id":"c","label":"Cram each slide with as much text as possible","is_correct":false,"explanation":"Crammed slides are the most common deck mistake. Strong slides make one clear point."}]}$lum$::jsonb, NULL),
  ($lum$2546632d-7a7f-533e-94fd-637bf5a685d2$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"When editing your own writing with AI, what is the key thing to protect?","options":[{"id":"a","label":"Your voice and meaning, so the edit improves the writing without making it sound like a stranger","is_correct":true,"explanation":"Structural editing should tighten and clarify while keeping it unmistakably yours."},{"id":"b","label":"The original word count, no matter what","is_correct":false,"explanation":"Length is flexible. Voice and meaning are what matter."},{"id":"c","label":"Every sentence exactly as you first wrote it","is_correct":false,"explanation":"Editing means changing things. The goal is to keep your voice, not every word."}]}$lum$::jsonb, NULL),
  ($lum$acfe0fa4-9979-59ae-98fc-468245985e53$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"You want a strong image from a single sentence. What helps most?","options":[{"id":"a","label":"Describing the subject, the style, the mood, and key details rather than a bare noun","is_correct":true,"explanation":"Specific, layered descriptions guide the result far better than a single word."},{"id":"b","label":"Typing one word and hoping for the best","is_correct":false,"explanation":"One word leaves almost everything to chance. Detail steers the output."},{"id":"c","label":"Asking for the most complicated image possible","is_correct":false,"explanation":"Complexity is not the goal. A clear, specific description is."}]}$lum$::jsonb, NULL),
  ($lum$3dcd5f22-74bc-5c33-900e-37238a968ccd$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 6, $lum$fill_blank$lum$, $lum${"template":"To get AI to write in your voice, the most reliable move is to paste real {{1}} of your own writing for it to copy.","blanks":[{"id":"1","accept":["samples","examples"],"ideal":"samples"}],"explanation":"Examples teach the AI your voice better than any description alone."}$lum$::jsonb, NULL),
  ($lum$4a6a0871-8a2e-5496-9b06-cf67d4aa933f$lum$::uuid, $lum$a1c6ff75-925a-535a-aad9-b28e2365cd92$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"A first draft from AI is usually a starting {{1}}, not a finished piece, so your job is to shape it.","blanks":[{"id":"1","accept":["point","block","draft"],"ideal":"point"}],"explanation":"The draft gets you past the blank page. The shaping is where your judgment turns it into something good."}$lum$::jsonb, NULL),
  ($lum$c5f6d678-9c3b-523b-a8d6-a2bb55c4c429$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"What is an AI workflow, in plain terms?","options":[{"id":"a","label":"A single giant prompt that tries to do an entire job at once","is_correct":false,"explanation":"That is the opposite. A workflow breaks the job into clear, single-purpose steps."},{"id":"b","label":"A repeatable task broken into clear steps with a reusable prompt for each","is_correct":true,"explanation":"Set it up once, then run the same steps every time. Like a recipe you do not reinvent."},{"id":"c","label":"A one-time question you never use again","is_correct":false,"explanation":"The value of a workflow is reuse. A one-off question is not a workflow."}]}$lum$::jsonb, NULL),
  ($lum$8bd7691c-7931-5a89-b83a-585a92e544f5$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"Which task is the best first candidate to hand to AI?","options":[{"id":"a","label":"A high-stakes legal filing where an undetected error is costly","is_correct":false,"explanation":"High cost of error and hard to catch makes a task a poor solo fit for AI."},{"id":"b","label":"A repetitive, text-based task that follows a pattern and whose output you can quickly check","is_correct":true,"explanation":"Repetitive, text-heavy, pattern-following, and easy to verify is the sweet spot."},{"id":"c","label":"A sensitive HR conversation requiring real judgment","is_correct":false,"explanation":"Genuine human judgment and relationship work stays with you."}]}$lum$::jsonb, NULL),
  ($lum$b7acc9c4-1d25-5380-94f5-dac549c4249c$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"What is the right way to use AI for competitive analysis?","options":[{"id":"a","label":"Ask the AI to recall facts about a competitor from memory","is_correct":false,"explanation":"It will confidently invent prices and features. Never rely on its recall for specifics."},{"id":"b","label":"Gather real material yourself, then have AI organize and find patterns in it","is_correct":true,"explanation":"You bring the facts, AI brings the structure and pattern-spotting."},{"id":"c","label":"Trust whatever comparison it produces without checking","is_correct":false,"explanation":"Organized does not mean accurate. Sanity-check standout claims against your source."}]}$lum$::jsonb, NULL),
  ($lum$7aea165c-2ac0-5a6b-82eb-c2aa6088ceb5$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"Why build reusable AI templates for your team's common messages?","options":[{"id":"a","label":"So routine writing becomes quick fill-in-the-blank work and stays consistent","is_correct":true,"explanation":"Templating frequent messages saves time and keeps quality steady even on a busy day."},{"id":"b","label":"So the team never has to read what they send","is_correct":false,"explanation":"Templates speed up writing, they do not remove the need to review."},{"id":"c","label":"So every message sounds completely different each time","is_correct":false,"explanation":"Templates aim for consistency, not random variation."}]}$lum$::jsonb, NULL),
  ($lum$a176c0d1-9b4f-56a7-95ee-119245d381c7$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"What keeps an AI workflow reliable over time?","options":[{"id":"a","label":"Making each step do one thing, saving the prompts, and keeping a review checkpoint","is_correct":true,"explanation":"Small single-purpose steps, reusable prompts, and a human checkpoint make a workflow dependable."},{"id":"b","label":"Rewriting every prompt from scratch each time you run it","is_correct":false,"explanation":"Then it saves no time. The point is to reuse saved prompts."},{"id":"c","label":"Removing every point where a human reviews the output","is_correct":false,"explanation":"You still approve the result. The workflow speeds the work, it does not replace your sign-off."}]}$lum$::jsonb, NULL),
  ($lum$d85bfa77-e0de-5f1c-80b2-ffecfcf057e1$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What makes a team template one people will actually use?","options":[{"id":"a","label":"It is clever and complex so it shows off what AI can do","is_correct":false,"explanation":"Adoption beats cleverness. A complex template tends to sit unused."},{"id":"b","label":"It solves a frequent shared pain, has obvious blanks, and lives where the team already works","is_correct":true,"explanation":"Build for the busy Tuesday user and make using it easier than not."},{"id":"c","label":"It is stored somewhere private only you can find","is_correct":false,"explanation":"A template no one can find does not get used. Put it where work happens."}]}$lum$::jsonb, NULL),
  ($lum$4fbb62a2-a463-5297-9042-edf1432ed4d3$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 6, $lum$fill_blank$lum$, $lum${"template":"For competitive analysis, you gather the real material yourself and let AI {{1}} it into a clear comparison.","blanks":[{"id":"1","accept":["organize","organise","structure"],"ideal":"organize"}],"explanation":"You bring the facts, AI brings the organization and pattern-spotting."}$lum$::jsonb, NULL),
  ($lum$76e176a3-6788-5425-a86b-7a23c5407cd8$lum$::uuid, $lum$1af5bdf8-9563-5ddc-ba20-4269a3605c42$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"A workflow only saves time if you {{1}} your prompts so you do not rewrite them every run.","blanks":[{"id":"1","accept":["save","store","reuse"],"ideal":"save"}],"explanation":"Saved, reusable prompts are what make a workflow pay off week after week."}$lum$::jsonb, NULL),
  ($lum$aeccd69f-cb40-55e6-afc3-be177383d63b$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"In regulated fields like healthcare and law, what is AI's correct role?","options":[{"id":"a","label":"A source of authority you can cite directly","is_correct":false,"explanation":"AI is never a source of professional authority. It invents citations and misstates rules."},{"id":"b","label":"A capable assistant for drafting and organizing, with a qualified human responsible for the work","is_correct":true,"explanation":"AI assists; the professional verifies and stays accountable."},{"id":"c","label":"A replacement for professional judgment","is_correct":false,"explanation":"Judgment and accountability never transfer to the tool."}]}$lum$::jsonb, NULL),
  ($lum$ad3c112e-8a2a-5add-9a01-ec1edd3d08a0$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"An AI returns case citations to support a legal argument. What must you do?","options":[{"id":"a","label":"Use them, since the citations look complete","is_correct":false,"explanation":"AI fabricates realistic citations. People have been sanctioned for filing fake ones."},{"id":"b","label":"Verify each case in a real legal database and discard any that do not check out","is_correct":true,"explanation":"Every citation must be confirmed in an authoritative source, not the same AI tool."},{"id":"c","label":"Ask the AI to confirm they are real and trust its answer","is_correct":false,"explanation":"It will often confirm cases it invented. Verification must come from a real source."}]}$lum$::jsonb, NULL),
  ($lum$16419a74-0634-50b9-bb2f-0828a5f8633a$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"How should you handle confidential client or patient details with a public AI tool?","options":[{"id":"a","label":"Paste them in, then delete the chat afterward","is_correct":false,"explanation":"Deleting does not undo the disclosure. The data was already sent to an outside service."},{"id":"b","label":"Genericize the details, or use an approved private tool for sensitive content","is_correct":true,"explanation":"Strip identifiers for public tools, and keep truly confidential work in an approved private tool."},{"id":"c","label":"Paste them but instruct the AI to keep them private","is_correct":false,"explanation":"An instruction does not control the company's data policy. The data is still exposed."}]}$lum$::jsonb, NULL),
  ($lum$ba595d57-a2e7-56e2-b550-5572568af73a$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"What is the safe way to summarize a contract with AI?","options":[{"id":"a","label":"Ask it to summarize a standard contract from memory","is_correct":false,"explanation":"It will invent plausible terms. Always work from the real pasted text."},{"id":"b","label":"Paste the actual text, ask for specific terms in plain language, then verify against the document","is_correct":true,"explanation":"Work from the real text and confirm each summarized term, since a misread can flip the meaning."},{"id":"c","label":"Trust the summary without rereading the clauses","is_correct":false,"explanation":"A misread 'shall not' as 'shall' changes everything. Verify against the source."}]}$lum$::jsonb, NULL),
  ($lum$63da278a-63cd-560c-b603-8975f0f07413$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"How does AI best help with document review in a professional setting?","options":[{"id":"a","label":"By making the final judgment about what is material","is_correct":false,"explanation":"The review judgment is yours. AI helps you prepare and organize, it does not decide."},{"id":"b","label":"By building a review checklist beforehand and organizing your findings afterward","is_correct":true,"explanation":"AI handles the checklist and the structuring; your trained judgment handles the review."},{"id":"c","label":"By reviewing the documents entirely on its own","is_correct":false,"explanation":"It should not. The professional judgment and accountability stay with you."}]}$lum$::jsonb, NULL),
  ($lum$f55177b6-f671-59be-abc5-cb808c960832$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"Why is AI well suited to turning clinical or technical jargon into plain language?","options":[{"id":"a","label":"Because rephrasing and reframing text is one of its core strengths","is_correct":true,"explanation":"Translating dense language into plain terms for patients or clients is a strong, low-risk use."},{"id":"b","label":"Because it always knows the patient's full history","is_correct":false,"explanation":"It only knows what you give it. It does not have private context by default."},{"id":"c","label":"Because it can make medical decisions for you","is_correct":false,"explanation":"It cannot. Clinical decisions stay with the qualified professional."}]}$lum$::jsonb, NULL),
  ($lum$5ebe930b-f47d-56eb-b190-f49b1773f07e$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 6, $lum$fill_blank$lum$, $lum${"template":"In legal and clinical work, every citation, rule, or specific from AI must be {{1}} against an authoritative source before you rely on it.","blanks":[{"id":"1","accept":["verified","confirmed","checked"],"ideal":"verified"}],"explanation":"AI is not a source of authority, so the specifics always get confirmed against the real source."}$lum$::jsonb, NULL),
  ($lum$19544251-a119-59cd-bc48-acf3097af8bf$lum$::uuid, $lum$83954681-0b16-591d-a023-705348bc1d29$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"Before using a public AI tool on sensitive work, remove the identifying details, a practice called making the input {{1}}.","blanks":[{"id":"1","accept":["generic","anonymous"],"ideal":"generic"}],"explanation":"Genericizing lets you get help while keeping confidential details off a public tool."}$lum$::jsonb, NULL),
  ($lum$350f8896-745f-570a-a9b7-34a7eda81964$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 0, $lum$multiple_choice$lum$, $lum${"stem":"What is prompt chaining?","options":[{"id":"a","label":"Writing one enormous prompt that asks for everything at once","is_correct":false,"explanation":"That is the overloaded approach chaining replaces. Each goal gets done only half-well."},{"id":"b","label":"Breaking a task into focused steps where each step's output feeds the next","is_correct":true,"explanation":"Like an assembly line, each prompt does one thing well and passes the result along."},{"id":"c","label":"Asking the same question repeatedly until you like the answer","is_correct":false,"explanation":"Chaining is a sequence of different focused steps, not the same question repeated."}]}$lum$::jsonb, NULL),
  ($lum$cd10fe20-246b-52ab-aa73-ff6463719949$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 1, $lum$multiple_choice$lum$, $lum${"stem":"What is the main advantage of a checkpoint between chain steps?","options":[{"id":"a","label":"You catch and fix problems before they get baked into a long final output","is_correct":true,"explanation":"Reviewing the outline before drafting saves you from compounding errors."},{"id":"b","label":"It lets the AI work without any input from you","is_correct":false,"explanation":"Checkpoints are exactly where you steer. They keep you involved, not removed."},{"id":"c","label":"It makes the task take longer for no reason","is_correct":false,"explanation":"It saves time overall by preventing rework on a flawed foundation."}]}$lum$::jsonb, NULL),
  ($lum$b0793fd9-aaf9-5e38-9839-7496b594a157$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 2, $lum$multiple_choice$lum$, $lum${"stem":"What belongs in your personal AI toolkit?","options":[{"id":"a","label":"Saved go-to prompts, custom instructions, and documented reusable routines","is_correct":true,"explanation":"A toolkit turns your best discoveries into reusable assets instead of one-off wins."},{"id":"b","label":"A single prompt you delete after each use","is_correct":false,"explanation":"The whole point is to keep what works, not throw it away."},{"id":"c","label":"Other people's passwords","is_correct":false,"explanation":"That is not part of a toolkit and is unsafe. The toolkit is prompts and setups."}]}$lum$::jsonb, NULL),
  ($lum$8d1a2bed-88e0-5d95-9699-3449412353be$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 3, $lum$multiple_choice$lum$, $lum${"stem":"What do custom instructions let you do?","options":[{"id":"a","label":"Set standing context once so every conversation starts already tuned to you","is_correct":true,"explanation":"Who you are, your preferred format, and your tone, applied to every chat automatically."},{"id":"b","label":"Make the AI browse the live web","is_correct":false,"explanation":"That is a separate capability. Custom instructions are persistent personal context."},{"id":"c","label":"Avoid ever writing a prompt again","is_correct":false,"explanation":"You still write prompts. Custom instructions just give them a better starting point."}]}$lum$::jsonb, NULL),
  ($lum$1fdabc71-924e-5ae9-88c0-49f4775219cb$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 4, $lum$multiple_choice$lum$, $lum${"stem":"When should you chain prompts instead of using a single one?","options":[{"id":"a","label":"When the task has distinct stages, the output is long, or getting it wrong is expensive","is_correct":true,"explanation":"Distinct stages and high stakes are exactly when chaining pays off."},{"id":"b","label":"Only for the very shortest, simplest questions","is_correct":false,"explanation":"Simple one-shot questions do not need a chain. Complex multi-stage work does."},{"id":"c","label":"Never, since one prompt is always better","is_correct":false,"explanation":"One overloaded prompt produces mediocre results on complex tasks."}]}$lum$::jsonb, NULL),
  ($lum$54dff319-0606-52dd-8fea-a130fe808dd6$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 5, $lum$multiple_choice$lum$, $lum${"stem":"What is the guiding principle for building team templates?","options":[{"id":"a","label":"Adoption beats cleverness: build for the busy user and make using it easier than not","is_correct":true,"explanation":"A simple template people use daily delivers more value than a brilliant one left unused."},{"id":"b","label":"Complexity beats simplicity, since complex templates look more impressive","is_correct":false,"explanation":"Complex templates tend to go unused. Simplicity drives adoption."},{"id":"c","label":"Quantity beats quality: launch with thirty templates at once","is_correct":false,"explanation":"Start small with a few strong ones and iterate based on what people ask for."}]}$lum$::jsonb, NULL),
  ($lum$28f52bde-02ba-5feb-8904-285b6d5a74a9$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 6, $lum$fill_blank$lum$, $lum${"template":"Prompt chaining works because each focused step does one thing well, and the output of one becomes the {{1}} to the next.","blanks":[{"id":"1","accept":["input"],"ideal":"input"}],"explanation":"Connecting steps so each feeds the next is what makes a chain more than a list."}$lum$::jsonb, NULL),
  ($lum$0c2d317d-2005-5097-8e8a-be0d909b57a4$lum$::uuid, $lum$e2d98ab7-c4df-54cd-9426-4f912fc8906b$lum$::uuid, 7, $lum$fill_blank$lum$, $lum${"template":"A team template gets used when its fill-in parts are obvious, so mark them clearly with {{1}}.","blanks":[{"id":"1","accept":["brackets","placeholders"],"ideal":"brackets"}],"explanation":"Clear bracketed blanks make a template fill-in-the-blank rather than interpret-the-intent."}$lum$::jsonb, NULL)
